// PURPOSE: Read the invoice image and prepare it for Gemini's inlineData format.
// Works for both the Google Drive watch path AND the direct Form Upload path.
// Requires: N8N_DEFAULT_BINARY_DATA_MODE=default in your Docker environment.

// Get source info from whichever trigger fired
let mimeType, fileName;
try {
  mimeType = $('Watch Invoice Folder').item.json.mimeType;
  fileName = $('Watch Invoice Folder').item.json.name;
} catch(e) {
  mimeType = $('Normalize Form Upload').item.json.mimeType;
  fileName = $('Normalize Form Upload').item.json.name;
}

const binaryKey = Object.keys($input.item.binary || {})[0];
if (!binaryKey) {
  throw new Error('No binary data found — check the Download File or Form Upload node ran successfully');
}

const binaryData = $input.item.binary[binaryKey];

// In memory mode (N8N_DEFAULT_BINARY_DATA_MODE=default), binaryData.data is real base64
return {
  json: {
    mimeType:   mimeType,
    base64Data: binaryData.data,
    fileName:   binaryData.fileName || fileName
  }
};

