// PURPOSE: Parse Gemini's JSON response, validate required fields, normalise types.
// Works for both Google Drive and Form Upload trigger paths.
//
// Input:  Gemini API response  { candidates: [{ content: { parts: [{ text: "..." }] } }] }
// Output (success): { valid: true, invoice_number, invoice_date, total_amount, ... }
// Output (failure): { valid: false, error: "...", source_file: "..." }

// Get source info from whichever trigger fired
let sourceName, sourceId;
try {
  sourceName = $('Watch Invoice Folder').item.json.name;
  sourceId   = $('Watch Invoice Folder').item.json.id;
} catch(e) {
  sourceName = $('Normalize Form Upload').item.json.name;
  sourceId   = $('Normalize Form Upload').item.json.id || 'form-upload';
}

// ── Step 1: Extract text from Gemini response ─────────────────────────────
const responseContent = $input.item.json.candidates?.[0]?.content?.parts?.[0]?.text;

if (!responseContent) {
  return {
    json: {
      valid: false,
      error: 'Gemini returned no content — check your API key and model name',
      source_file: sourceName
    }
  };
}

// ── Step 2: Parse JSON ────────────────────────────────────────────────────
let invoice;
try {
  invoice = JSON.parse(responseContent);
} catch (e) {
  return {
    json: {
      valid: false,
      error: `Gemini response could not be parsed as JSON: ${e.message}`,
      raw_response: responseContent.substring(0, 500),
      source_file: sourceName
    }
  };
}

// ── Step 3: Validate required fields ─────────────────────────────────────
const requiredFields = ['invoice_number', 'invoice_date', 'vendor_name', 'total_amount'];
const missingFields  = requiredFields.filter(f => !invoice[f]);

if (missingFields.length > 0) {
  return {
    json: {
      valid: false,
      error: `AI could not extract required fields: ${missingFields.join(', ')}`,
      raw_response: responseContent.substring(0, 500),
      source_file: sourceName
    }
  };
}

// ── Step 4: Normalise and return clean structured data ────────────────────
return {
  json: {
    valid:           true,
    invoice_number:  String(invoice.invoice_number  || ''),
    invoice_date:    String(invoice.invoice_date    || ''),
    due_date:        String(invoice.due_date        || ''),
    vendor_name:     String(invoice.vendor_name     || ''),
    vendor_address:  String(invoice.vendor_address  || ''),
    vendor_email:    String(invoice.vendor_email    || ''),
    bill_to_company: String(invoice.bill_to_company || ''),
    bill_to_address: String(invoice.bill_to_address || ''),
    line_items:      JSON.stringify(invoice.line_items || []),
    subtotal:        Number(invoice.subtotal)     || 0,
    tax_amount:      Number(invoice.tax_amount)   || 0,
    total_amount:    Number(invoice.total_amount) || 0,
    currency:        String(invoice.currency      || 'USD'),
    payment_terms:   String(invoice.payment_terms || ''),
    notes:           String(invoice.notes         || ''),
    source_file:     sourceName,
    source_file_id:  sourceId,
    processed_at:    new Date().toISOString()
  }
};

// PURPOSE: Validate and normalize the file uploaded via the form trigger.
// Renames the binary key to 'data' so downstream nodes (Extract PDF Text,
// Prepare Image Data) find it under the same key that Google Drive downloads use.

const binaryKey = Object.keys($input.item.binary || {})[0];
if (!binaryKey) {
  throw new Error('No file was uploaded. Please select a PDF or image file.');
}

const binaryData = $input.item.binary[binaryKey];
const mimeType   = binaryData.mimeType || 'application/octet-stream';

if (!mimeType.startsWith('image/') && mimeType !== 'application/pdf') {
  throw new Error(
    `Unsupported file type: ${mimeType}. Please upload a PDF or image (JPG, PNG, WEBP).`
  );
}

// Rename to 'data' — matches the binary key Google Drive's Download File node uses,
// so Extract PDF Text and Prepare Image Data work identically for both paths.
return {
  json: {
    mimeType: mimeType,
    name:     binaryData.fileName || `upload-${Date.now()}.${mimeType.split('/')[1] || 'bin'}`,
    id:       `form-upload-${Date.now()}`,
    source:   'form-upload'
  },
  binary: { data: binaryData }
};
